  kind: FieldKind           // Type of field
  name: string
  isRequired: boolean
  isList: boolean           // Is array type []
  isUnique: boolean
  isId: boolean             // Primary key
  isReadOnly: boolean
  isGenerated?: boolean
  isUpdatedAt?: boolean
  type: string              // e.g., "String", "Int", "BigInt", "User" (model ref)
  nativeType?: [string, string[]] | null  // e.g., ['VarChar', ['191']]
  dbName?: string | null
  hasDefaultValue: boolean
  default?: FieldDefault | FieldDefaultScalar | FieldDefaultScalar[]

  // Relation fields
  relationFromFields?: string[]  // Local FK fields
  relationToFields?: string[]    // Remote PK fields
  relationOnDelete?: string      // CASCADE, SET_NULL, etc.
  relationOnUpdate?: string
  relationName?: string          // @relation name
  documentation?: string
}
```

---

## Generator Architecture

### Entry Point: `GeneratorOptions`
(`packages/generator/src/configuration.ts`)

Generators receive options containing:

```typescript
export type GeneratorOptions = {
  generator: GeneratorConfig        // Generator configuration
  dmmf: DMMF.Document              // The complete DMMF document
  schemaPath: string               // Path to schema.prisma file
  datamodel: string                // Raw schema.prisma content
  datasources: DataSource[]        // Database connections
  version: string                  // Engine version hash
  binaryPaths?: BinaryPaths        // Path to engine binaries
  typedSql?: SqlQueryOutput[]      // Typed SQL queries if enabled
}
```

### Generator Handler Implementation
(`packages/generator-helper/src/generatorHandler.ts`)

Generators implement a simple interface:

```typescript
export interface Handler {
  onGenerate(options: GeneratorOptions): Promise<any>
  onManifest?(config: GeneratorConfig): GeneratorManifest | Promise<GeneratorManifest>
}

// Called via JSON-RPC from the Prisma CLI
export function generatorHandler(handler: Handler): void {
  // Reads JSON-RPC messages from stdin
  // Calls handler.onGenerate() when 'generate' method is invoked
  // Writes responses to stderr
}
```

---

## Real-World Generator Usage: Prisma Client JS

### Step 1: Entry Point (`packages/client-generator-js/src/generator.ts`)

```typescript
export class PrismaClientJsGenerator implements Generator {
  async generate(options: GeneratorOptions): Promise<void> {
    const outputDir = parseEnvValue(options.generator.output!)

    await generateClient({
      dmmf: options.dmmf,           // Pass DMMF to generator
      datamodel: options.datamodel,
      schemaPath: options.schemaPath,
      outputDir,
      generator: options.generator,
      // ... more options
    })
  }
}
```

### Step 2: Build Client (`packages/client-generator-js/src/generateClient.ts`)

Creates in-memory representation of files as a `FileMap` object:

```typescript
export interface FileMap {
  [name: string]: string | FileMap  // Files or subdirectories
}

// Generate code using TSClient class
const nodeClient = new TSClient(nodeClientOptions)

const fileMap: FileMap = {
  'index.js': JS(nodeClient),           // JavaScript output
  'index.d.ts': TS(nodeClient),         // TypeScript definitions
  'default.js': JS(defaultClient),
  'package.json': JSON.stringify(pkgJson),
  'schema.prisma': datamodel,
}

// Write all files to disk
await writeFileMap(outputDir, fileMap)
```

### Step 3: Iterate Over Models (`packages/client-generator-js/src/TSClient/TSClient.ts`)

```typescript
public toTS(): string {
  // Create a Model generator for each model/type in DMMF
  const modelAndTypes = Object.values(this.dmmf.typeAndModelMap).reduce((acc, modelOrType) => {
    if (this.dmmf.outputTypeMap.model[modelOrType.name]) {
      acc.push(new Model(modelOrType, context))  // Create Model generator
    }
    return acc
  }, [] as Model[])

  // Generate code for each model
  const code = `
    ${modelAndTypes.map((m) => m.toTSWithoutNamespace()).join('\n')}
  `
}
```

### Step 4: Generate Per-Model Code (`packages/client-generator-js/src/TSClient/Model.ts`)

The `Model` class iterates over model fields:

```typescript
export class Model implements Generable {
  constructor(
    protected readonly model: DMMF.Model,
    protected readonly context: GenerateContext,
  ) {
    this.type = context.dmmf.outputTypeMap.model[model.name]
    this.mapping = context.dmmf.mappings.modelOperations.find((m) => m.model === model.name)
  }

  // For each CRUD operation (create, read, update, delete):
  protected get argsTypes(): ts.Export<ts.TypeDeclaration>[] {
    const argsTypes: ts.Export<ts.TypeDeclaration>[] = []
    for (const action of Object.keys(DMMF.ModelAction)) {
      const fieldName = this.rootFieldNameForAction(action)
      const field = this.dmmf.rootFieldMap[fieldName]  // Get schema field for operation
      // Build type definitions based on schema field arguments
    }
  }
}
```

### Step 5: Process Model Fields (`packages/client-generator-js/src/TSClient/Payload.ts`)

Example showing field iteration:

```typescript
export function buildModelPayload(model: DMMF.Model, context: GenerateContext) {
  const scalars = ts.objectType()
  const objects = ts.objectType()
  const composites = ts.objectType()

  // Iterate over all fields in the model
  for (const field of model.fields) {
    if (field.kind === 'object') {
      // Relation field
      if (context.dmmf.isComposite(field.type)) {
        composites.add(buildModelOutputProperty(field, context.dmmf))
      } else {
        objects.add(buildModelOutputProperty(field, context.dmmf))
      }
    } else if (field.kind === 'enum' || field.kind === 'scalar') {
      // Scalar or enum field
      scalars.add(buildModelOutputProperty(field, context.dmmf))
    }
  }

  return ts.moduleExport(typeDeclaration)
}
```

### Step 6: Global Iteration (`packages/client-generator-js/src/TSClient/globalOmit.ts`)

Creating types for all models:

```typescript
export function globalOmitConfig(dmmf: DMMFHelper) {
  const objectType = ts.objectType().addMultiple(
    dmmf.datamodel.models.map((model) => {
      const type = ts.namedType(getOmitName(model.name))
      return ts.property(uncapitalize(model.name), type).optional()
    }),
  )

  return ts.moduleExport(ts.typeDeclaration('GlobalOmitConfig', objectType))
}
```

### Step 7: PrismaClient Type Map (`packages/client-generator-js/src/TSClient/PrismaClient.ts`)

```typescript
function clientTypeMapModelsDefinition(context: GenerateContext) {
  const modelNames = context.dmmf.datamodel.models.map((m) => m.name)

  const model = ts.objectType()

  model.addMultiple(
    modelNames.map((modelName) => {
      const entry = ts.objectType()
      entry.add(ts.property('payload', ts.namedType(getPayloadName(modelName))))

      const actions = getModelActions(context.dmmf, modelName)
      const operations = ts.objectType()
      operations.addMultiple(
        actions.map((action) => {
          // Create operation type for each action
          return ts.property(action, operationType)
        }),
      )
      return ts.property(modelName, entry)
    }),
  )
}
```

---

## File Writing Pattern

All generators use a recursive file writing utility:

```typescript
async function writeFileMap(outputDir: string, fileMap: FileMap) {
  return Promise.all(
    Object.entries(fileMap).map(async ([fileName, content]) => {
      const absolutePath = path.join(outputDir, fileName)

      if (typeof content === 'string') {
        // Write file
        await fs.writeFile(absolutePath, content)
      } else {
        // Create subdirectory and recurse
        await fs.mkdir(absolutePath)
        await writeFileMap(absolutePath, content)
      }
    }),
  )
}
```

---

## Key Paths in Codebase

| Path | Purpose |
|------|---------|
| `/packages/dmmf/src/dmmf.ts` | DMMF type definitions |
| `/packages/generator/src/configuration.ts` | GeneratorOptions and GeneratorConfig types |
| `/packages/generator-helper/src/generatorHandler.ts` | JSON-RPC handler for generators |
| `/packages/client-generator-js/src/generator.ts` | Prisma Client JS generator entry point |
| `/packages/client-generator-js/src/generateClient.ts` | Main generation logic and file writing |
| `/packages/client-generator-js/src/TSClient/TSClient.ts` | Model iteration and code generation orchestration |
| `/packages/client-generator-js/src/TSClient/Model.ts` | Per-model type generation |
| `/packages/client-generator-js/src/dmmf.ts` | DMMFHelper utility class for querying DMMF |

---

## Summary Pattern

1. **Generator receives DMMF document** via `GeneratorOptions.dmmf`
2. **Iterate models**: `dmmf.datamodel.models.map(model => ...)`
3. **Iterate fields**: `model.fields.map(field => ...)`
4. **Classify fields**: Check `field.kind` (scalar, object, enum, unsupported)
5. **Build types**: Use DMMF to generate TypeScript/JavaScript code strings
6. **Create FileMap**: Organize code into nested object structure
7. **Write files**: Use `fs.writeFile()` recursively via `writeFileMap()`

The DMMF is the **single source of truth** for schema information that drives all code generation.

