import type { DMMF } from '@prisma/dmmf'

const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Int: 'number',
  Float: 'number',
  Boolean: 'boolean',
  DateTime: 'Date',
  BigInt: 'bigint',
  Decimal: 'number',
  Json: 'unknown',
  Bytes: 'Uint8Array',
}

/** Converts a DMMF field to its TypeScript type string, including list and nullability modifiers. */
export function fieldTypeToTs(field: DMMF.Field): string {
  const base = SCALAR_TYPE_MAP[field.type] ?? field.type
  const withList = field.isList ? `${base}[]` : base
  return field.isRequired ? withList : `${withList} | null`
}

/** Emits an exported TypeScript interface for a DMMF model. */
export function modelToInterface(model: DMMF.Model): string {
  const fields = model.fields
    .map((f) => {
      const optional = !f.isRequired && !f.isList ? '?' : ''
      const tsType = fieldTypeToTs(f)
      return `  ${f.name}${optional}: ${tsType}`
    })
    .join('\n')

  return `export interface ${model.name} {\n${fields}\n}`
}

/** Emits an exported TypeScript union type for a DMMF enum. */
export function enumToUnion(e: DMMF.DatamodelEnum): string {
  const values = e.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${e.name} = ${values}`
}

/** Returns the names of all ID fields in a model. */
export function modelIdFields(model: DMMF.Model): string[] {
  return model.fields.filter((f) => f.isId).map((f) => f.name)
}

/** Lowercases the first character of a string (e.g. `User` → `user`). */
function uncapitalize(s: string): string {
  return s.charAt(0).toLowerCase() + s.slice(1)
}

/** Returns a `Pick<Model, 'id1' | 'id2'>` type string for the model's ID fields. */
function whereType(model: DMMF.Model): string {
  const ids = modelIdFields(model)
  if (ids.length === 0) {
    return `Partial<${model.name}>`
  }
  const keys = ids.map((id) => `'${id}'`).join(' | ')
  return `Pick<${model.name}, ${keys}>`
}

/**
 * Emits a block of CRUD methods (findMany, findUnique, create, update, delete)
 * typed against the given model. This string is intended to be used as the
 * value of a property on `RestClient`.
 */
export function modelToCrudMethods(model: DMMF.Model): string {
  const name = model.name
  const where = whereType(model)

  const idFields = modelIdFields(model)
  const pathParam =
    idFields.length > 0
      ? idFields.map((id) => `\${params.where.${id}}`).join('/')
      : 'unknown'

  const resourcePath = `/${uncapitalize(name)}s`

  return [
    `    findMany: (params?: {`,
    `      skip?: number`,
    `      take?: number`,
    `      where?: Partial<${name}>`,
    `    }): Promise<${name}[]> => this.#request('GET', '${resourcePath}', params),`,
    ``,
    `    findUnique: (params: { where: ${where} }): Promise<${name} | null> =>`,
    `      this.#request('GET', \`${resourcePath}/${pathParam}\`),`,
    ``,
    `    create: (params: { data: Omit<${name}, ${idFields.map((id) => `'${id}'`).join(' | ') || 'never'}>; }): Promise<${name}> =>`,
    `      this.#request('POST', '${resourcePath}', params.data),`,
    ``,
    `    update: (params: { where: ${where}; data: Partial<Omit<${name}, ${idFields.map((id) => `'${id}'`).join(' | ') || 'never'}>>; }): Promise<${name}> =>`,
    `      this.#request('PATCH', \`${resourcePath}/${pathParam}\`, params.data),`,
    ``,
    `    delete: (params: { where: ${where} }): Promise<${name}> =>`,
    `      this.#request('DELETE', \`${resourcePath}/${pathParam}\`),`,
  ].join('\n')
}

/** Assembles the complete `rest-client.ts` file content from DMMF models and enums. */
export function generateRestClientFile(
  models: readonly DMMF.Model[],
  enums: readonly DMMF.DatamodelEnum[],
): string {
  const parts: string[] = []

  parts.push('// Generated by @prisma/generator-rest-client — do not edit manually')
  parts.push('')

  for (const e of enums) {
    parts.push(enumToUnion(e))
    parts.push('')
  }

  for (const model of models) {
    parts.push(modelToInterface(model))
    parts.push('')
  }

  parts.push(`export interface RestClientConfig {`)
  parts.push(`  baseUrl: string`)
  parts.push(`  headers?: Record<string, string>`)
  parts.push(`}`)
  parts.push('')

  const modelProperties = models
    .map((model) => {
      const propName = uncapitalize(model.name)
      const methods = modelToCrudMethods(model)
      return `  readonly ${propName} = {\n${methods}\n  }`
    })
    .join('\n\n')

  parts.push(`export class RestClient {`)
  parts.push(`  readonly #config: RestClientConfig`)
  parts.push('')
  parts.push(`  constructor(config: RestClientConfig) {`)
  parts.push(`    this.#config = config`)
  parts.push(`  }`)
  parts.push('')
  parts.push(modelProperties)
  parts.push('')
  parts.push(`  #request<T>(method: string, path: string, body?: unknown): Promise<T> {`)
  parts.push(`    return fetch(\`\${this.#config.baseUrl}\${path}\`, {`)
  parts.push(`      method,`)
  parts.push(`      headers: { 'Content-Type': 'application/json', ...this.#config.headers },`)
  parts.push(`      body: body ? JSON.stringify(body) : undefined,`)
  parts.push(`    }).then((res) => res.json() as Promise<T>)`)
  parts.push(`  }`)
  parts.push(`}`)
  parts.push('')

  return parts.join('\n')
}

