  const where = whereType(model)

  const idFields = modelIdFields(model)
  const pathParam =
    idFields.length > 0
      ? idFields.map((id) => `\${params.where.${id}}`).join('/')
      : 'unknown'

  const resourcePath = `/${uncapitalize(name)}s`

  return [
    `    findMany: (params?: {`,
    `      skip?: number`,
    `      take?: number`,
    `      where?: Partial<${name}>`,
    `    }): Promise<${name}[]> => this.#request('GET', '${resourcePath}', params),`,
    ``,
    `    findUnique: (params: { where: ${where} }): Promise<${name} | null> =>`,
    `      this.#request('GET', \`${resourcePath}/${pathParam}\`),`,
    ``,
    `    create: (params: { data: Omit<${name}, ${idFields.map((id) => `'${id}'`).join(' | ') || 'never'}>; }): Promise<${name}> =>`,
    `      this.#request('POST', '${resourcePath}', params.data),`,
    ``,
    `    update: (params: { where: ${where}; data: Partial<Omit<${name}, ${idFields.map((id) => `'${id}'`).join(' | ') || 'never'}>>; }): Promise<${name}> =>`,
    `      this.#request('PATCH', \`${resourcePath}/${pathParam}\`, params.data),`,
    ``,
    `    delete: (params: { where: ${where} }): Promise<${name}> =>`,
    `      this.#request('DELETE', \`${resourcePath}/${pathParam}\`),`,
  ].join('\n')
}

/** Assembles the complete `rest-client.ts` file content from DMMF models and enums. */
export function generateRestClientFile(
  models: readonly DMMF.Model[],
  enums: readonly DMMF.DatamodelEnum[],
): string {
  const parts: string[] = []

  parts.push('// Generated by @prisma/generator-rest-client — do not edit manually')
  parts.push('')

  for (const e of enums) {
    parts.push(enumToUnion(e))
    parts.push('')
  }

  for (const model of models) {
    parts.push(modelToInterface(model))
    parts.push('')
  }

  parts.push(`export interface RestClientConfig {`)
  parts.push(`  baseUrl: string`)
  parts.push(`  headers?: Record<string, string>`)
  parts.push(`}`)
  parts.push('')

  const modelProperties = models
    .map((model) => {
      const propName = uncapitalize(model.name)
      const methods = modelToCrudMethods(model)
      return `  readonly ${propName} = {\n${methods}\n  }`
    })
    .join('\n\n')

  parts.push(`export class RestClient {`)
  parts.push(`  readonly #config: RestClientConfig`)
  parts.push('')
  parts.push(`  constructor(config: RestClientConfig) {`)
  parts.push(`    this.#config = config`)
  parts.push(`  }`)
  parts.push('')
  parts.push(modelProperties)
  parts.push('')
  parts.push(`  #request<T>(method: string, path: string, body?: unknown): Promise<T> {`)
  parts.push(`    return fetch(\`\${this.#config.baseUrl}\${path}\`, {`)
  parts.push(`      method,`)
  parts.push(`      headers: { 'Content-Type': 'application/json', ...this.#config.headers },`)
  parts.push(`      body: body ? JSON.stringify(body) : undefined,`)
  parts.push(`    }).then((res) => res.json() as Promise<T>)`)
  parts.push(`  }`)
  parts.push(`}`)
  parts.push('')

  return parts.join('\n')
}

